   155	APSPResult floyd_warshall(const Graph& g) {
   156	    APSPResult res;
   157	    auto ids = g.node_ids();
   158	    const size_t n = ids.size();
   159	
   160	    std::unordered_map<NodeId, size_t> index;
   161	    index.reserve(n);
   162	    for (size_t i = 0; i < n; i++) {
   163	        index[ids[i]] = i;
   164	    }
   165	
   166	    auto offset = [n](size_t row, size_t col) {
   167	        return row * n + col;
   168	    };
   169	
   170	    std::vector<double> dist(n * n, INF_WEIGHT);
   171	    std::vector<NodeId> next(n * n, INVALID_NODE);
   172	
   173	    for (size_t i = 0; i < n; i++) {
   174	        dist[offset(i, i)] = 0.0;
   175	    }
   176	
   177	    for (size_t i = 0; i < n; i++) {
   178	        NodeId u = ids[i];
   179	        for (auto& e : g.out_edges(u)) {
   180	            auto dst_it = index.find(e.dst);
   181	            if (dst_it == index.end()) continue;
   182	
   183	            size_t j = dst_it->second;
   184	            size_t edge_pos = offset(i, j);
   185	            if (e.weight < dist[edge_pos]) {
   186	                dist[edge_pos] = e.weight;
   187	                next[edge_pos] = e.dst;
   188	            }
   189	        }
   190	    }
   191	
   192	    for (size_t k = 0; k < n; k++) {
   193	        for (size_t i = 0; i < n; i++) {
   194	            size_t ik = offset(i, k);
   195	            if (dist[ik] == INF_WEIGHT) continue;
   196	
   197	            for (size_t j = 0; j < n; j++) {
   198	                size_t kj = offset(k, j);
   199	                if (dist[kj] == INF_WEIGHT) continue;
   200	
   201	                size_t ij = offset(i, j);
   202	                double through_k = dist[ik] + dist[kj];
   203	                if (through_k < dist[ij]) {
   204	                    dist[ij] = through_k;
   205	                    next[ij] = next[ik];
   206	                }
   207	            }
   208	        }
   209	    }
   210	
   211	    for (size_t i = 0; i < n; i++) {
   212	        auto& row_dist = res.dist[ids[i]];
   213	        auto& row_next = res.next[ids[i]];
   214	        row_dist.reserve(n);
   215	        row_next.reserve(n);
   216	
   217	        for (size_t j = 0; j < n; j++) {
   218	            row_dist[ids[j]] = dist[offset(i, j)];
   219	            row_next[ids[j]] = next[offset(i, j)];
   220	        }
   221	    }
   222	
   223	    return res;
   224	}
