   104	std::vector<NodeId> find_path(const Graph& g, NodeId src, NodeId dst) {
   105	    if (src == dst && g.has_node(src)) return {src};
   106	    if (!g.has_node(src) || !g.has_node(dst)) return {};
   107	
   108	    std::queue<NodeId> q;
   109	    std::unordered_map<NodeId, NodeId> parent;
   110	    q.push(src);
   111	    parent[src] = INVALID_NODE;
   112	
   113	    while (!q.empty()) {
   114	        NodeId cur = q.front();
   115	        q.pop();
   116	        for (auto& e : g.out_edges(cur)) {
   117	            if (parent.count(e.dst)) continue;
   118	            parent[e.dst] = cur;
   119	            if (e.dst == dst) {
   120	                std::vector<NodeId> path;
   121	                NodeId c = dst;
   122	                while (c != INVALID_NODE) {
   123	                    path.push_back(c);
   124	                    c = parent[c];
   125	                }
   126	                std::reverse(path.begin(), path.end());
   127	                return path;
   128	            }
   129	            q.push(e.dst);
   130	        }
   131	    }
   132	    return {};
   133	}
