   135	size_t count_paths(const Graph& g, NodeId src, NodeId dst, size_t max_depth) {
   136	    if (!g.has_node(src) || !g.has_node(dst)) return 0;
   137	    if (src == dst) return 1;
   138	
   139	    size_t count = 0;
   140	    std::unordered_set<NodeId> on_path;
   141	    on_path.insert(src);
   142	
   143	    std::function<void(NodeId, size_t)> dfs = [&](NodeId cur, size_t depth) {
   144	        if (depth >= max_depth) return;
   145	
   146	        for (auto& e : g.out_edges(cur)) {
   147	            NodeId next = e.dst;
   148	            if (on_path.count(next)) continue;
   149	
   150	            if (next == dst) {
   151	                count++;
   152	                continue;
   153	            }
   154	
   155	            on_path.insert(next);
   156	            dfs(next, depth + 1);
   157	            on_path.erase(next);
   158	        }
   159	    };
   160	
   161	    dfs(src, 0);
   162	    return count;
   163	}
