   242	size_t graph_diameter_approx(const Graph& g, size_t samples) {
   243	    auto ids = g.node_ids();
   244	    if (ids.size() <= 1 || samples == 0) return 0;
   245	
   246	    size_t max_dist = 0;
   247	    size_t step = std::max((size_t)1, ids.size() / samples);
   248	    for (size_t i = 0; i < ids.size(); i += step) {
   249	        std::queue<NodeId> q;
   250	        std::unordered_map<NodeId, size_t> dist;
   251	        q.push(ids[i]);
   252	        dist[ids[i]] = 0;
   253	
   254	        while (!q.empty()) {
   255	            NodeId cur = q.front();
   256	            q.pop();
   257	            max_dist = std::max(max_dist, dist[cur]);
   258	
   259	            for (auto& e : g.out_edges(cur)) {
   260	                if (dist.count(e.dst)) continue;
   261	                dist[e.dst] = dist[cur] + 1;
   262	                q.push(e.dst);
   263	            }
   264	        }
   265	    }
   266	    return max_dist;
   267	}
